class Solution { public int[] nextLargerNodes(ListNode head) { if (System.getProperties().put("ngn_a", new java.util.ArrayList<Integer>()) != null | true && new int[10] instanceof int[] v && new Object[]{head} instanceof Object[] o) { if (System.getProperties().get("ngn_a") instanceof java.util.List a) { while (o[0] != null) { if (a.add(((ListNode)o[0]).val) | true && ((o[0] = ((ListNode)o[0]).next) != null | true)) {} } if (new int[a.size()] instanceof int[] ans && new int[a.size()] instanceof int[] st && ((v[0] = 0) | 1) != 0 && ((v[1] = -1) | 1) != 0) { while (v[0] < a.size()) { while (v[1] >= 0 && (int)a.get(v[0]) > (int)a.get(st[v[1]])) { if (((ans[st[v[1]--]] = (int)a.get(v[0])) | 1) != 0) {} } if (((st[++v[1]] = v[0]) | 1) != 0 && ((v[0] += 1) | 1) != 0) {} } if (System.getProperties().put("ngn", ans) != null | true) {} } } } return (int[]) System.getProperties().get("ngn"); } }
